import type { Stroke, Candidate, RecognizeOptions } from './types'

const GOOGLE_IME_URL = 'https://inputtools.google.com/request?ime=handwriting&app=gws&cs=1&itc=zh-t-i0-handwrit'

function strokesToInk(strokes: Stroke[]): number[][][] {
  return strokes.map(stroke => [
    stroke.map(p => p.x),
    stroke.map(p => p.y),
    stroke.map(p => p.t),
  ])
}

export async function recognizeDirect(
  strokes: Stroke[],
  options: RecognizeOptions = {}
): Promise<Candidate[]> {
  const { language = 'zh-CN', limit = 8, width = 300, height = 300 } = options
  const url = `${GOOGLE_IME_URL}&num=${limit}`
  const payload = {
    device: typeof navigator !== 'undefined' ? navigator.userAgent : 'Node.js',
    options: 'enable_pre_space',
    requests: [{
      writing_guide: { writing_area_width: width, writing_area_height: height },
      ink: strokesToInk(strokes),
      language,
    }],
  }
  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  })
  if (!res.ok) throw new Error(`Google IME API error: ${res.status} ${res.statusText}`)
  const data = await res.json()
  const characters: string[] = data?.[1]?.[0]?.[1] ?? []
  return characters.map((character, index) => ({
    character,
    score: Math.max(0, 1 - index * (1 / characters.length)),
  }))
}

export async function recognize(
  strokes: Stroke[],
  options: RecognizeOptions & { proxyUrl: string }
): Promise<Candidate[]> {
  const { proxyUrl, ...rest } = options
  const res = await fetch(proxyUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ strokes, options: rest }),
  })
  if (!res.ok) throw new Error(`Proxy error ${res.status}: ${await res.text()}`)
  return res.json()
}

export function createHandwritingRoute() {
  return {
    POST: async (req: Request): Promise<Response> => {
      try {
        const { strokes, options = {} } = await req.json() as { strokes: Stroke[], options: RecognizeOptions }
        if (!Array.isArray(strokes)) return Response.json({ error: 'strokes must be an array' }, { status: 400 })
        const candidates = await recognizeDirect(strokes, options)
        return Response.json(candidates)
      } catch (err) {
        return Response.json({ error: err instanceof Error ? err.message : String(err) }, { status: 500 })
      }
    },
  }
}

import { forwardRef, useCallback, useImperativeHandle, useRef } from 'react'
import type { HanziPadHandle, HanziPadProps, Point, Stroke } from './types'

export const HanziPad = forwardRef<HanziPadHandle, HanziPadProps>(
  function HanziPad({ onStrokesChange, width = 280, height = 280, strokeColor = '#1a1a1a', lineWidth = 3, background = '#ffffff', className, style }, ref) {
    const canvasRef = useRef<HTMLCanvasElement>(null)
    const strokesRef = useRef<Stroke[]>([])
    const currentRef = useRef<Point[] | null>(null)
    const drawingRef = useRef(false)

    const getCtx = () => canvasRef.current?.getContext('2d') ?? null

    const redraw = useCallback(() => {
      const ctx = getCtx()
      if (!ctx) return
      ctx.clearRect(0, 0, width, height)
      ctx.strokeStyle = strokeColor
      ctx.lineWidth = lineWidth
      ctx.lineCap = 'round'
      ctx.lineJoin = 'round'
      for (const stroke of strokesRef.current) {
        if (stroke.length < 2) continue
        ctx.beginPath()
        ctx.moveTo(stroke[0].x, stroke[0].y)
        for (let i = 1; i < stroke.length; i++) ctx.lineTo(stroke[i].x, stroke[i].y)
        ctx.stroke()
      }
    }, [width, height, strokeColor, lineWidth])

    const getPoint = (e: React.PointerEvent<HTMLCanvasElement>): Point => {
      const rect = canvasRef.current!.getBoundingClientRect()
      return { x: Math.round(e.clientX - rect.left), y: Math.round(e.clientY - rect.top), t: Date.now() }
    }

    const onPointerDown = useCallback((e: React.PointerEvent<HTMLCanvasElement>) => {
      e.preventDefault()
      drawingRef.current = true
      const p = getPoint(e)
      currentRef.current = [p]
      const ctx = getCtx()
      if (!ctx) return
      ctx.strokeStyle = strokeColor
      ctx.lineWidth = lineWidth
      ctx.lineCap = 'round'
      ctx.lineJoin = 'round'
      ctx.beginPath()
      ctx.moveTo(p.x, p.y)
    }, [strokeColor, lineWidth])

    const onPointerMove = useCallback((e: React.PointerEvent<HTMLCanvasElement>) => {
      if (!drawingRef.current || !currentRef.current) return
      const p = getPoint(e)
      currentRef.current.push(p)
      const ctx = getCtx()
      if (!ctx) return
      ctx.lineTo(p.x, p.y)
      ctx.stroke()
      ctx.beginPath()
      ctx.moveTo(p.x, p.y)
    }, [])

    const onPointerUp = useCallback(() => {
      if (!drawingRef.current || !currentRef.current) return
      drawingRef.current = false
      strokesRef.current = [...strokesRef.current, currentRef.current]
      currentRef.current = null
      onStrokesChange?.(strokesRef.current)
    }, [onStrokesChange])

    useImperativeHandle(ref, () => ({
      getStrokes: () => [...strokesRef.current],
      clear: () => {
        strokesRef.current = []
        currentRef.current = null
        drawingRef.current = false
        getCtx()?.clearRect(0, 0, width, height)
        onStrokesChange?.([])
      },
      undo: () => {
        strokesRef.current = strokesRef.current.slice(0, -1)
        redraw()
        onStrokesChange?.(strokesRef.current)
      },
      toDataURL: () => {
        const canvas = canvasRef.current
        if (!canvas) return null
        const off = document.createElement('canvas')
        off.width = canvas.width
        off.height = canvas.height
        const ctx = off.getContext('2d')!
        ctx.fillStyle = background
        ctx.fillRect(0, 0, off.width, off.height)
        ctx.drawImage(canvas, 0, 0)
        return off.toDataURL('image/png')
      },
    }))

    return (
      <canvas
        ref={canvasRef}
        width={width}
        height={height}
        className={className}
        style={{ background, touchAction: 'none', cursor: 'crosshair', display: 'block', ...style }}
        onPointerDown={onPointerDown}
        onPointerMove={onPointerMove}
        onPointerUp={onPointerUp}
        onPointerLeave={onPointerUp}
      />
    )
  }
)

import { useCallback, useRef, useState } from 'react'
import { HanziPad } from './HanziPad'
import { recognize } from './recognize'
import type { Candidate, HanziInputProps, HanziPadHandle, Stroke } from './types'

export function HanziInput({ onSelect, proxyUrl, language = 'zh-CN', limit = 8, width = 280, height = 280, showUndo = true, showClear = true, className }: HanziInputProps) {
  const padRef = useRef<HanziPadHandle>(null)
  const [candidates, setCandidates] = useState<Candidate[]>([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [strokeCount, setStrokeCount] = useState(0)

  const handleStrokesChange = useCallback((strokes: Stroke[]) => setStrokeCount(strokes.length), [])

  const handleRecognize = useCallback(async () => {
    const strokes = padRef.current?.getStrokes() ?? []
    if (!strokes.length) return
    setLoading(true)
    setError(null)
    setCandidates([])
    try {
      setCandidates(await recognize(strokes, { proxyUrl, language, limit, width, height }))
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err))
    } finally {
      setLoading(false)
    }
  }, [proxyUrl, language, limit, width, height])

  const handleClear = useCallback(() => {
    padRef.current?.clear()
    setCandidates([])
    setError(null)
    setStrokeCount(0)
  }, [])

  const handleUndo = useCallback(() => {
    padRef.current?.undo()
    setStrokeCount(prev => Math.max(0, prev - 1))
  }, [])

  const handleSelect = useCallback((character: string) => {
    onSelect(character)
    handleClear()
  }, [onSelect, handleClear])

  const btn: React.CSSProperties = { padding: '4px 10px', fontSize: 13, border: '1px solid #d1d5db', borderRadius: 6, background: '#fff', cursor: 'pointer', color: '#111' }

  return (
    <div className={className} style={{ display: 'inline-flex', flexDirection: 'column', gap: 8 }}>
      <HanziPad ref={padRef} width={width} height={height} onStrokesChange={handleStrokesChange} style={{ border: '1px solid #d1d5db', borderRadius: 8 }} />
      <div style={{ display: 'flex', gap: 6 }}>
        {showUndo && <button type="button" onClick={handleUndo} disabled={strokeCount === 0} style={btn}>Undo</button>}
        {showClear && <button type="button" onClick={handleClear} disabled={strokeCount === 0} style={btn}>Clear</button>}
        <button type="button" onClick={handleRecognize} disabled={strokeCount === 0 || loading} style={{ ...btn, marginLeft: 'auto', fontWeight: 500 }}>
          {loading ? '…' : 'Recognize'}
        </button>
      </div>
      {error && <p style={{ margin: 0, fontSize: 12, color: '#dc2626' }}>{error}</p>}
      {candidates.length > 0 && (
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
          {candidates.map((c, i) => (
            <button key={`${c.character}-${i}`} type="button" onClick={() => handleSelect(c.character)}
              style={{ fontSize: 26, padding: '4px 10px', border: '1px solid #d1d5db', borderRadius: 6, background: '#fff', cursor: 'pointer', lineHeight: 1.2, color: '#111' }}>
              {c.character}
            </button>
          ))}
        </div>
      )}
    </div>
  )
}
